DSR_fil_Valid_RecordsOut AS ( SELECT exp_InitialOut.SSN AS SSN, exp_InitialOut.NAME AS NAME, exp_InitialOut.CURRENT_ACCT AS CURRENT_ACCT, exp_InitialOut.CURRENT_ORG AS CURRENT_ORG, exp_InitialOut.FLSA_STATUS AS FLSA_STATUS, exp_InitialOut.COMP_TIME_CUR_BAL AS COMP_TIME_CUR_BAL, exp_InitialOut.COMP_TIME_YEAR_EARNED AS COMP_TIME_YEAR_EARNED, exp_InitialOut.PP_END_DATE AS PP_END_DATE, exp_InitialOut.DAILY_DATE_EARNED AS DAILY_DATE_EARNED, exp_InitialOut.COMP_TIME_RATE AS COMP_TIME_RATE, exp_InitialOut.COMP_TIME_HOURS AS COMP_TIME_HOURS, exp_InitialOut.COMP_TIME_UNDEF AS COMP_TIME_UNDEF, exp_InitialOut.o_CURR_PP_FLAG AS CURR_PP_FLAG, exp_InitialOut.o_VALID_RECORD_FLAG AS VALID_RECORD_FLAG FROM exp_InitialOut AS exp_InitialOut),

fil_Valid_RecordsOut AS ( SELECT * FROM DSR_fil_Valid_RecordsOut AS DSR_fil_Valid_RecordsOut WHERE VALID_RECORD_FLAG = TRUE),

