DSR_exp_FinalOut AS ( SELECT exp_ConvertOut.o_PP_END_YEAR AS PP_END_YEAR, exp_ConvertOut.o_PP_NUM AS PP_NUM, exp_ConvertOut.o_PP_YEAR_NUM AS PP_YEAR_NUM, exp_ConvertOut.SSN AS SSN, exp_ConvertOut.NAME AS NAME, exp_ConvertOut.CURRENT_ACCT AS CURRENT_ACCT, exp_ConvertOut.CURRENT_ORG AS CURRENT_ORG, exp_ConvertOut.FLSA_STATUS AS FLSA_STATUS, exp_ConvertOut.COMP_TIME_CUR_BAL AS COMP_TIME_CUR_BAL, exp_ConvertOut.COMP_TIME_YEAR_EARNED AS COMP_TIME_YEAR_EARNED, exp_ConvertOut.o_PP_END_DATE AS PP_END_DATE, exp_ConvertOut.o_DAILY_DATE_EARNED AS DAILY_DATE_EARNED, exp_ConvertOut.COMP_TIME_RATE AS COMP_TIME_RATE, exp_ConvertOut.COMP_TIME_HOURS AS COMP_TIME_HOURS, exp_ConvertOut.COMP_TIME_UNDEF AS COMP_TIME_UNDEF FROM exp_ConvertOut AS exp_ConvertOut),

exp_FinalOut AS ( SELECT PP_END_YEAR AS PP_END_YEAR, PP_NUM AS PP_NUM, PP_YEAR_NUM AS PP_YEAR_NUM, SSN AS SSN, NAME AS NAME, CURRENT_ACCT AS CURRENT_ACCT, CURRENT_ORG AS CURRENT_ORG, FLSA_STATUS AS FLSA_STATUS, COMP_TIME_CUR_BAL AS COMP_TIME_CUR_BAL, COMP_TIME_YEAR_EARNED AS COMP_TIME_YEAR_EARNED, PP_END_DATE AS PP_END_DATE, DAILY_DATE_EARNED AS DAILY_DATE_EARNED, COMP_TIME_RATE AS COMP_TIME_RATE, COMP_TIME_HOURS AS COMP_TIME_HOURS, COMP_TIME_UNDEF AS COMP_TIME_UNDEF FROM DSR_exp_FinalOut AS DSR_exp_FinalOut)


Select 
